# Search for a prime number
def check_prime(n):
    if n < 2:
        print(n, "is not prime")
        return
    for i in range(2, n):
        if n % i == 0:
            print(n, "is not prime (divisible by", str(i) + ")")
            break
    else:
        print(n, "is prime")

check_prime(17)
check_prime(24)
check_prime(2)

